// DownloadAllBestEffort download the platform bundle and extract every library file it contains.
//
// Unlike [`ensure_languages`], this does not check the manifest language list
// against archive contents — it simply extracts all `.so`/`.dylib`/`.dll` files
// from the bundle. Languages in the manifest that are missing from the archive
// are silently ignored rather than returning an error.
//
// Returns the number of library files extracted (including those already cached).
func (h *DownloadManager) DownloadAllBestEffort() (*uint, error) {
	ptr := C.ts_pack_download_manager_download_all_best_effort((*C.TS_PACKDownloadManager)(unsafe.Pointer(h.ptr)))
	if err := lastError(); err != nil {
		return nil, err
	}
	return func() *uint { v := uint(ptr); return &v }(), nil
}

// CleanCache remove all cached parser libraries.
func (h *DownloadManager) CleanCache() error {
	C.ts_pack_download_manager_clean_cache((*C.TS_PACKDownloadManager)(unsafe.Pointer(h.ptr)))
	return lastError()
}
